import { Marker, Popup } from "react-leaflet";
import L from "leaflet";

export default function PlaneMarker({ position, flightData }) {
  if (!flightData) return null;

  const icon = L.divIcon({
    html: `<img 
      src="https://cdn-icons-png.flaticon.com/512/34/34627.png"
      style="width:30px; transform: rotate(${flightData.velocity}deg);" 
    />`,
    className: "",
  });

  return (
    <Marker position={position} icon={icon}>
      <Popup>
        ✈️ {flightData.callsign}<br />
        Alt: {Math.round(flightData.altitude)}<br />
        Speed: {Math.round(flightData.velocity)}
      </Popup>
    </Marker>
  );
}
